    14→
    15→interface SourceFormProps {
    16→  initial?: Source;
    17→  projectId?: string;
    18→  onSubmit: (input: SourceInput) => Promise<void>;
    19→  title: string;
    20→  redirectTo?: string;
    21→  onSuccess?: () => void;
    22→  onCancel?: () => void;
    23→}
    24→
    25→
    26→export function SourceForm({ initial, onSubmit, title, redirectTo, onSuccess, onCancel }: SourceFormProps) {
    27→  const router = useRouter();
    28→  const [saving, setSaving] = useState(false);
    29→  const [error, setError] = useState("");
    30→  const [provider, setProvider] = useState(initial?.provider ?? "dockerhub");
    31→  const [repository, setRepository] = useState(initial?.repository ?? "");
    32→  const [pollInterval, setPollInterval] = useState(String(initial?.poll_interval_seconds ?? 86400));
    33→  const [enabled, setEnabled] = useState(initial?.enabled ?? true);
    34→  const [configJson, setConfigJson] = useState(
    35→    JSON.stringify(initial?.config ?? {}, null, 2)
    36→  );
    37→
    38→  const handleSubmit = async (e: React.FormEvent) => {
    39→    e.preventDefault();
    40→    setError("");
    41→
    42→    const repoError = validateRepository(provider, repository);
    43→    if (repoError) {
    44→      setError(repoError);
    45→      return;
    46→    }
    47→
    48→    let parsedConfig: Record<string, unknown> | undefined;
    49→    if (configJson.trim() && configJson.trim() !== "{}") {
    50→      try {
    51→        parsedConfig = JSON.parse(configJson);
    52→      } catch {
    53→        setError("Config must be valid JSON");
    54→        return;
    55→      }
    56→    }
    57→
    58→    setSaving(true);
    59→    try {
    60→      await onSubmit({
    61→        provider,
    62→        repository: repository.trim(),
    63→        poll_interval_seconds: Number(pollInterval),
    64→        enabled,
    65→        config: parsedConfig,
    66→      });
    67→      if (onSuccess) {
    68→        onSuccess();
    69→      } else {
    70→        router.push(redirectTo ?? "/sources");
    71→      }
    72→    } catch (err: unknown) {
    73→      setError(err instanceof Error ? err.message : "Failed to save");
    74→    } finally {
    75→      setSaving(false);
    76→    }
    77→  };
    78→
    79→  const handleCancel = () => {
    80→    if (onCancel) {
    81→      onCancel();
    82→    } else {
    83→      router.back();
    84→    }
    85→  };
    86→
    87→  const formContent = (
    88→    <form onSubmit={handleSubmit} className="space-y-4">
    89→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
    90→      <div className="space-y-2">
    91→        <Label>Provider</Label>
    92→        <Select value={provider} onValueChange={setProvider}>
    93→          <SelectTrigger><SelectValue /></SelectTrigger>
    94→          <SelectContent>
    95→            <SelectItem value="dockerhub">Docker Hub</SelectItem>
    96→            <SelectItem value="github">GitHub</SelectItem>
    97→          </SelectContent>
    98→        </Select>
    99→      </div>
   100→      <div className="space-y-2">
   101→        <Label htmlFor="repository">Repository</Label>
   102→        <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder="e.g. library/golang or ethereum/go-ethereum" required />
   103→      </div>
   104→      <div className="space-y-2">
   105→        <Label htmlFor="poll_interval">Poll Interval (seconds)</Label>
   106→        <Input id="poll_interval" type="number" min={60} value={pollInterval} onChange={(e) => setPollInterval(e.target.value)} />
   107→      </div>
   108→      <div className="space-y-2">
   109→        <Label htmlFor="config">Config (JSON, optional)</Label>
   110→        <Textarea
   111→          id="config"
   112→          value={configJson}
   113→          onChange={(e) => setConfigJson(e.target.value)}
   114→          rows={4}
   115→          className="font-mono text-sm"
   116→          placeholder="{}"
   117→        />
   118→      </div>
   119→      <div className="flex items-center gap-3">
   120→        <Switch checked={enabled} onCheckedChange={setEnabled} />
   121→        <Label>Enabled</Label>
   122→      </div>
   123→      <div className="flex justify-end gap-2">
   124→        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
   125→        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   126→      </div>
   127→    </form>
   128→  );
   129→
   130→  if (onSuccess) {
   131→    return formContent;
   132→  }
   133→
   134→  return (
   135→    <Card className="mx-auto max-w-2xl">
   136→      <CardHeader><CardTitle>{title}</CardTitle></CardHeader>
   137→      <CardContent>
   138→        {formContent}
   139→      </CardContent>
   140→    </Card>
   141→  );
   142→}
