    37→function formatDuration(startedAt?: string, completedAt?: string): string {
    38→  if (!startedAt) return "--";
    39→  const start = new Date(startedAt).getTime();
    40→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    41→  const secs = Math.round((end - start) / 1000);
    42→  if (secs < 60) return `${secs}s`;
    43→  const mins = Math.floor(secs / 60);
    44→  const rem = secs % 60;
    45→  return `${mins}m ${rem}s`;
    46→}
    47→
    48→function truncate(str: string, max: number): string {
    49→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
